import*as Instance from"./instance.js";const outputFormats={},toOutputFormat=(t,r)=>{if(r in outputFormats)return outputFormats[r](t);throw Error(`The '${r}' error format is not supported`)};outputFormats.FLAG=t=>({valid:t.valid}),outputFormats.BASIC=t=>{const r={valid:t.valid};if(!t.valid){r.errors=[];for(const s of Instance.allNodes(t))for(var[o,a]of Object.entries(s.errors).reverse())s.valid||r.errors.unshift({keyword:a,absoluteKeywordLocation:o,instanceLocation:Instance.uri(s),valid:s.valid});r.errors.pop()}return r};export{toOutputFormat};